import{_ as s,o as a,c as i,a6 as d}from"./chunks/framework.B6HGZFrS.js";const k=JSON.parse('{"title":"依赖分析","description":"","frontmatter":{"layout":"doc","title":"依赖分析"},"headers":[],"relativePath":"guide/dependency-inspection.md","filePath":"guide/dependency-inspection.md","lastUpdated":1780302832000}'),t={name:"guide/dependency-inspection.md"};function n(o,e,l,c,p,r){return a(),i("div",null,[...e[0]||(e[0]=[d('<h1 id="依赖分析" tabindex="-1">依赖分析 <a class="header-anchor" href="#依赖分析" aria-label="Permalink to “依赖分析”">​</a></h1><p>项目集成 <a href="https://github.com/antfu/node-modules-inspector" target="_blank" rel="noreferrer"><code>node-modules-inspector</code></a> 用于观察依赖体积、依赖关系和可优化空间。</p><h2 id="常用命令" tabindex="-1">常用命令 <a class="header-anchor" href="#常用命令" aria-label="Permalink to “常用命令”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">npm</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> run</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> deps:inspect</span></span></code></pre></div><p>启动交互式依赖分析页面，默认监听 <code>http://127.0.0.1:9999</code>。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">npm</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> run</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> deps:build</span></span></code></pre></div><p>构建静态分析页面到 <code>.node-modules-inspector/</code>，该目录仅用于本地排查，不提交到仓库。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>查找体积较大的直接依赖与传递依赖。</li><li>判断某个开发依赖是否还能移除或替换。</li><li>在升级构建工具、测试工具或文档工具后，对比依赖树变化。</li></ul><h2 id="版本说明" tabindex="-1">版本说明 <a class="header-anchor" href="#版本说明" aria-label="Permalink to “版本说明”">​</a></h2><p>当前固定使用 <code>node-modules-inspector@1.4.2</code>。<code>2.0.x</code> 会通过 <code>devframe</code> 引入低采用率的 <code>logs-sdk</code>，<code>2.1.x</code> 版本暂时依赖尚未发布到 npm 的 <code>publint@^0.3.21</code>，在 npm 安装时会失败；等上游发布修复后再升级。</p><p>项目当前提交并维护 <code>package-lock.json</code>。如果后续需要在 CI 中增加依赖快照校验，可以再评估接入 <code>node-modules-inspector check</code>；本次仅提供交互式分析和静态报告构建命令。</p>',12)])])}const g=s(t,[["render",n]]);export{k as __pageData,g as default};
